func (wal *bootstrappedWAL) InMemoryRaftLog() *raft.InMemoryRaftLog {
	s := raft.NewInMemoryRaftLog()
	if wal.snapshot != nil {
		s.ApplySnapshot(*wal.snapshot)
	}
	if wal.st != nil {
		s.SetHardState(*wal.st)
	}
	if len(wal.ents) != 0 {
		s.Append(wal.ents)
	}
	return s
}

// MemoryStorage is deprecated, use InMemoryRaftLog instead.
func (wal *bootstrappedWAL) MemoryStorage() *raft.InMemoryRaftLog {
	return wal.InMemoryRaftLog()
}

